import os
import sqlite3
import re
import time
from flask import Flask, render_template, request, jsonify, session, redirect, url_for
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

# Rate limiting state
last_request_time = {}

def get_db_connection():
    conn = sqlite3.connect(Config.DATABASE_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def waf_check(payload):
    if not payload:
        return True

    # 1. Block ALL whitespace (Space, Tab, Newline, etc.)
    if any(c.isspace() for c in payload):
        return False

    upper_payload = payload.upper()

    # 2. Block comments, UNION, and advanced concatenation bypasses
    # These are critical for SQLite exploitation when spaces are restricted
    blacklist = ['--', '/*', '*/', '#', 'UNION', 'JOIN', 'SLEEP', '||', 'LIKE', 'GLOB', 'IN', 'ATTACH']
    for item in blacklist:
        if item in upper_payload:
            return False

    # 3. Context-aware logical operator check
    # Blocks 'OR' and 'AND' if they appear adjacent to operators/parentheses (dense SQL)
    if re.search(r'[^A-Z](OR|AND)[^A-Z]|^OR[^A-Z]|^AND[^A-Z]|[^A-Z]OR$|[^A-Z]AND$', upper_payload):
        return False

    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        # Credentials moved from UI hint to hidden config file
        if username == "admin" and password == "aetheris_dev_2024":
            session['user'] = 'admin'
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    conn = get_db_connection()
    components = conn.execute('SELECT * FROM engine_components LIMIT 5').fetchall()
    conn.close()
    return render_template('dashboard.html', components=components)

@app.route('/inventory')
def inventory():
    if 'user' not in session:
        return redirect(url_for('login'))
    conn = get_db_connection()
    parts = conn.execute('SELECT * FROM engine_parts').fetchall()
    conn.close()
    return render_template('inventory.html', parts=parts)

@app.route('/maintenance')
def maintenance():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('maintenance.html')

@app.route('/api/v1/maintenance/filter')
def api_filter_logs():
    if 'user' not in session:
        return jsonify({"error": "Unauthorized"}), 401

    # Rate limiting to prevent aggressive automated extraction
    ip = request.remote_addr
    now = time.time()
    if ip in last_request_time and now - last_request_time[ip] < 0.6:
        return jsonify({"error": "Rate limit exceeded"}), 429
    last_request_time[ip] = now

    sort_by = request.args.get('sort_by', 'timestamp')

    if not waf_check(sort_by):
        return jsonify({"error": "Security Violation: Pattern Restricted"}), 403

    try:
        conn = get_db_connection()
        # Hardened Blind SQLi: Result order changes, but no error details leaked
        query = f"SELECT id, timestamp, technician_id, engine_serial, action FROM maintenance_logs ORDER BY {sort_by} ASC"
        logs = conn.execute(query).fetchall()
        conn.close()
        return jsonify([dict(row) for row in logs])
    except Exception:
        # Suppressed error details to force purely blind exploitation
        return jsonify({"error": "Internal Server Error"}), 500

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

