{% extends 'base.html' %}
{% block content %}
<h2>Maintenance Logs</h2>
<div class="card">
    <div style="margin-bottom: 20px;">
        <label>Sort By:</label>
        <select id="sortSelector" onchange="loadLogs()">
            <option value="timestamp">Date/Time</option>
            <option value="technician_id">Technician ID</option>
            <option value="engine_serial">Engine Serial</option>
        </select>
    </div>
    <table id="logsTable">
        <thead>
            <tr>
                <th>ID</th>
                <th>Timestamp</th>
                <th>Tech ID</th>
                <th>Engine Serial</th>
                <th>Action Taken</th>
            </tr>
        </thead>
        <tbody id="logsBody">
            <!-- Loaded via API -->
        </tbody>
    </table>
</div>

<script>
function loadLogs() {
    const sortBy = document.getElementById('sortSelector').value;
    fetch(`/api/v1/maintenance/filter?sort_by=${sortBy}`)
        .then(res => res.json())
        .then(data => {
            const tbody = document.getElementById('logsBody');
            tbody.innerHTML = '';
            if (data.error) {
                tbody.innerHTML = `<tr><td colspan="5" style="color:red">${data.error}</td></tr>`;
                return;
            }
            data.forEach(log => {
                tbody.innerHTML += `<tr>
                    <td>${log.id}</td>
                    <td>${log.timestamp}</td>
                    <td>${log.technician_id}</td>
                    <td>${log.engine_serial}</td>
                    <td>${log.action}</td>
                </tr>`;
            });
        });
}
document.addEventListener('DOMContentLoaded', loadLogs);
</script>
{% endblock %}
